### 构建时预压缩（推荐）
```js
// vite.config.js
import viteCompression from 'vite-plugin-compression';

export default {
  plugins: [
    viteCompression({ algorithm: 'gzip' }),
    viteCompression({ algorithm: 'brotliCompress' }),
  ]
};
// 构建产物：app.js + app.js.gz + app.js.br
```

```nginx
# Nginx 优先提供预压缩文件
gzip_static on;
brotli_static on;
```

